#include <iostream>\n#include <cstdint>\n#include <string>\n\nint64_t static Pow(int64_t base, int64_t exp, int64_t mod) {\n  if (exp == 0) {\n    return 1;\n  }\n  if (exp % 2 == 0) {\n    auto p = Pow(base, exp / 2, mod) % mod;\n    return (p * p) % mod;\n  }\n  return base * Pow(base, exp - 1, mod) % mod;\n}\n\ntemplate <class T>\nstruct Node {\n  Node(const T p_value, Node* p_next = nullptr, Node* p_previous = nullptr) {\n    value = p_value;\n    next = p_next;\n    previous = p_previous;\n  }\n  T value;\n  Node* next;\n  Node* previous;\n};\n\nint64_t static Hash(const std::string& word) {\n  int64_t p = 1000000007LL;\n  int64_t x = 263;\n  int64_t h = 0;\n  size_t size = word.length();\n  for (size_t i = 0; i < size; i++) {\n    int64_t q = (word[i] * Pow(x, i, p)) % p;\n    h = (h + q) % p;\n  }\n  return h % p;\n}\n\ntemplate <class T, int64_t (*Hash)(const std::string& word)>\nclass HashTable {\n public:\n  HashTable(size_t size) {\n    Init(size);\n  }\n\n  ~HashTable() {\n    Free();\n  }\n\n  void Add(T value) {\n    if (!Find(value)) {\n      auto index = Hash(value) % size_;\n      auto old_node = table_[index];\n      auto new_node = new Node(value, old_node);\n      if (old_node) {\n        old_node->previous = new_node;\n      }\n      table_[index] = new_node;\n    }\n  }\n\n  void Delete(T value) {\n    if (Find(value)) {\n      auto index = Hash(value) % size_;\n      auto node = table_[index];\n      while (node && node->value != value) {\n        node = node->next;\n      }\n      if (node->previous) node->previous->next = node->next;\n      if (node->next) node->next->previous = node->previous;\n      if (node == table_[index]) table_[index] = node->next;\n      delete node;\n      node = nullptr;\n    }\n  }\n\n  bool Find(T value) {\n    auto index = Hash(value) % size_;\n    auto runner = table_[index];\n    while (runner) {\n      if (runner->value == value) {\n        return true;\n      }\n      runner = runner->next;\n    }\n    return false;\n  }\n\n  void Check(size_t index) {\n    auto runner = table_[index];\n    while (runner) {\n      std::cout << runner->value;\n      runner = runner->next;\n      if (runner) std::cout << ' ';\n    }\n    std::cout << std::endl;\n  }\n\n private:\n  void Init(size_t size) {\n    size_ = size;\n    table_ = new Node<T>*[size_]{};\n  }\n\n  void Free() {\n    for (size_t i = 0; i < size_; i++) {\n      auto runner = table_[i];\n      while (runner) {\n        auto next = runner->next;\n        delete runner;\n        runner = next;\n      }\n    }\n    delete[] table_;\n  }\n\n  size_t size_ = 0;\n  Node<T>** table_ = nullptr;\n};\n\nint main() {\n  int m, n;\n  std::cin >> m >> n;\n  HashTable<std::string, Hash> table(m);\n  for (int i = 0; i < n; i++) {\n    std::string command;\n    std::cin >> command;\n    if (command == \"check\") {\n      size_t index;\n      std::cin >> index;\n      table.Check(index);\n      continue;\n    }\n    std::string word;\n    std::cin >> word;\n    if (command == \"add\") {\n      table.Add(word);\n    } else if (command == \"del\") {\n      table.Delete(word);\n    } else {\n      if (table.Find(word)) {\n        std::cout << \"yes\" << std::endl;\n      } else {\n        std::cout << \"no\" << std::endl;\n      }\n    }\n  }\n  return 0;\n}